-- Get the first user's ID for demo enrollment
SET @userId = (SELECT id FROM users ORDER BY id LIMIT 1);
SET @comp3161Id = (SELECT id FROM courses WHERE courseCode = 'COMP3161' LIMIT 1);
SET @comp2140Id = (SELECT id FROM courses WHERE courseCode = 'COMP2140' LIMIT 1);
SET @comp2201Id = (SELECT id FROM courses WHERE courseCode = 'COMP2201' LIMIT 1);
SET @psyc2001Id = (SELECT id FROM courses WHERE courseCode = 'PSYC2001' LIMIT 1);

-- Enroll user in 4 courses (2 as student, 2 as class rep)
INSERT IGNORE INTO course_memberships (userId, courseId, membershipRole)
VALUES
  (@userId, @comp3161Id, 'class_rep'),
  (@userId, @comp2140Id, 'class_rep'),
  (@userId, @comp2201Id, 'student'),
  (@userId, @psyc2001Id, 'student');

-- Seed sample announcements for COMP3161
INSERT INTO course_announcements (courseId, authorId, announcementType, title, body, isOfficial, status, upvotes, downvotes)
VALUES
  (@comp3161Id, @userId, 'lecturer_late', 'Dr. Rowe will be 15 minutes late today', 'Please wait in the lecture theatre.', true, 'approved', 12, 1),
  (@comp3161Id, @userId, 'materials_uploaded', 'Week 5 slides uploaded to OurVLE', 'Check the course page for the latest lecture slides on normalization.', true, 'approved', 8, 0),
  (@comp3161Id, @userId, 'general', 'Midterm exam scheduled for March 20', 'The midterm will cover chapters 1-6. Open book format.', true, 'approved', 15, 2),
  (@comp3161Id, @userId, 'cancelled', 'Class cancelled due to public holiday', NULL, false, 'pending', 5, 0);

